import json
from kafka import KafkaConsumer
from functools import wraps

# Define a decorator to handle business logic execution
def execute_business_logic(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            func(*args, **kwargs)
        except Exception as e:
            print(f"Error executing business logic: {str(e)}")
    return wrapper

# Define a function to deserialize message values
def deserialize_message(message):
    try:
        return json.loads(message.value.decode('utf-8'))
    except Exception as e:
        print(f"Error deserializing message: {str(e)}")

# Initialize Kafka consumer with security configuration
